import subprocess

def convertDocument(input_file, output_file, output_format):
    try:
        # Construct the command to run LibreOffice in headless mode for conversion
        command = [
            'soffice',
            '--headless',
            '--convert-to', output_format,
            input_file,
            '--outdir', '.'
        ]
        
        # Execute the command using subprocess
        subprocess.run(command, check=True)
        
        # Rename the converted file to the desired output name
        import os
        base_name = os.path.splitext(input_file)[0]
        temp_output = f"{base_name}.{output_format}"
        os.rename(temp_output, output_file)
        
        print(f"Conversion successful: {input_file} -> {output_file}")
    except subprocess.CalledProcessError as e:
        print(f"Error during conversion: {e}")

# Example usage
convertDocument('input.docx', 'output.pdf', 'pdf')